12→int test(char* fname_src,
13→        char* fname_golden,
14→        uint16_t in_tensor_batch,
15→        uint16_t in_tensor_dim,
16→        uint16_t in_tensor_ch,
17→        uint16_t ker_dim,
18→        uint16_t pad,
19→        uint16_t stride,
20→        uint16_t out_tensor_dim)
21→{
22→    {
23→        dump_param("in_tensor_batch=%" PRIu16 ";in_tensor_dim=%" PRIu16
24→            ";in_tensor_ch=%" PRIu16 ";ker_dim=%" PRIu16 ";pad=%" PRIu16
25→            ";stride=%" PRIu16 ";out_tensor_dim=%" PRIu16, in_tensor_batch,
26→            in_tensor_dim, in_tensor_ch, ker_dim, pad, stride, out_tensor_dim);
27→    }
28→
29→    uint32_t src_len = (uint32_t)in_tensor_batch * in_tensor_ch * in_tensor_dim * in_tensor_dim;
30→    uint32_t out_len = (uint32_t)in_tensor_batch * in_tensor_ch * out_tensor_dim * out_tensor_dim;
31→
32→    FILE *fptr_src, *fptr_golden;
33→    //backup originally malloced starting address for later memory releasing
34→    void *src_ori, *out_ori, *golden_ori;
35→
36→    q7_t *src = (q7_t*)test_malloc(sizeof(q7_t) * src_len, "src", &src_ori);
37→    q7_t *out = (q7_t*)test_malloc(sizeof(q7_t) * out_len, "out", &out_ori);
38→    q7_t *golden = (q7_t*)test_malloc(sizeof(q7_t) * out_len, "golden", &golden_ori);
39→
40→    test_Fopen(fname_src, "rb", &fptr_src);
41→    test_Fread(src, sizeof(*src), src_len, fptr_src, "src");
42→    process_after_reading_input_data();
43→
44→#ifdef ENA_RUN_TWICE
45→    riscv_nn_avepool_HWC_s8(src, in_tensor_batch, in_tensor_dim, in_tensor_ch,
46→        ker_dim, pad, stride, out_tensor_dim, NULL, out);
47→#endif
48→
49→    process_before_perf_measuring();
50→#ifdef PF_COUNTER
51→    startPFM;
52→#endif
53→    riscv_nn_avepool_HWC_s8(src, in_tensor_batch, in_tensor_dim, in_tensor_ch,
54→        ker_dim, pad, stride, out_tensor_dim, NULL, out);
55→#ifdef PF_COUNTER
56→    stopPFM;
57→    readResult();
58→#endif
59→
60→#if ENA_DUMP_GOLDEN
61→    test_Fopen(fname_golden, "wb", &fptr_golden);
62→    fwrite(out, sizeof(*golden), out_len, fptr_golden);
63→    uint32_t retStatus = NDS_SUCCESS;
64→#else
65→    test_Fopen(fname_golden, "rb", &fptr_golden);
66→    test_Fread(golden, sizeof(*golden), out_len, fptr_golden, "golden");
67→    uint32_t retStatus = verify_buffer(out, golden, out_len, sizeof(*out), 0);
68→#endif
69→
70→    test_free(&src_ori);
71→    test_free(&out_ori);
72→    test_free(&golden_ori);
73→    fclose(fptr_src);
74→    fclose(fptr_golden);
75→
76→    return retStatus;
77→}
