79→int main (void)
80→{

 80→{
 81→    enable_fs_and_vs();
 82→    uint16_t in_tensor_batch, in_tensor_dim, in_tensor_ch, ker_dim, pad, stride,
 83→             out_tensor_dim;
 84→    uint32_t retStatus=NDS_SUCCESS;
 85→
 86→#if !ENA_MEASURE_PERF
 87→    //test-1 (assume pad_left=3, pad_top=3, pad_righ=5, pad_down=5)
 88→    in_tensor_batch = 3;
